// LexFlow — LEX Ingestion Validator
// Validates required fields from the POST body

const item = $input.first().json;
const body = item.body || item;

// Required fields
if (!body.file_id) {
  throw new Error('Validation failed: file_id is required (Google Drive file ID)');
}
if (!body.law_title) {
  throw new Error('Validation failed: law_title is required');
}

// Build clean payload with defaults
const payload = {
  file_id:   body.file_id.trim(),
  law_title: body.law_title.trim(),
  source:    (body.source || 'Official Gazette').trim(),
  year:      (body.year || String(new Date().getFullYear())).trim(),
  category:  (body.category || 'General').trim(),
  notes:     (body.notes || '').trim()
};

return [{ json: payload }];

// LexFlow — Duplicate Check
// Queries Supabase to see if this law_title already has embeddings stored.
// Prevents double-ingestion of the same document.

const item = $input.first().json;
const supabaseUrl = process.env.SUPABASE_URL || 'https://ncvlpqbevllqwrpdauxi.supabase.co';
const supabaseKey = process.env.SUPABASE_SERVICE_KEY || 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im5jdmxwcWJldmxscXdycGRhdXhpIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjE1NTk2NiwiZXhwIjoyMDg3NzMxOTY2fQ.Cs5k-uKtxyiTejLzsrpJllPg3-cZ6qvFDSjEdEVnBMU';

if (!supabaseKey) {
  // No credentials — skip duplicate check and proceed
  return [{ json: { ...item, _duplicate: false, _existing_count: 0 } }];
}

try {
  const encodedTitle = encodeURIComponent(item.law_title);
  const res = await fetch(
    `${supabaseUrl}/rest/v1/documents?select=id&metadata->>law_title=eq.${encodedTitle}&limit=1`,
    {
      headers: {
        'Authorization': `Bearer ${supabaseKey}`,
        'apikey': supabaseKey
      }
    }
  );

  if (!res.ok) {
    // If check fails, proceed anyway — don't block ingestion
    return [{ json: { ...item, _duplicate: false, _check_error: await res.text() } }];
  }

  const rows = await res.json();
  const isDuplicate = rows.length > 0;

  return [{ json: { ...item, _duplicate: isDuplicate, _existing_count: rows.length } }];

} catch (e) {
  // Network error — proceed anyway
  return [{ json: { ...item, _duplicate: false, _check_error: e.message } }];
}

