=={{ (function() {
  const rawText = $json.text || '';

  // Preserve PREAMBLE section
  const parts = rawText.split(/PREAMBLE/i);
  let result = parts.length > 1
    ? 'PREAMBLE ' + parts.slice(1).join('PREAMBLE')
    : rawText;

  // Roman numeral converter
  function romanToInt(roman) {
    const map = { 'I':1,'V':5,'X':10,'L':50,'C':100,'D':500,'M':1000 };
    let val = 0;
    const r = roman.toUpperCase();
    for (let i = 0; i < r.length; i++) {
      const curr = map[r[i]];
      const next = map[r[i+1]];
      if (!curr) return null;
      val += (next && curr < next) ? -curr : curr;
    }
    return val;
  }

  // Convert Roman numerals after legal keywords
  result = result.replace(
    /\b(Article|Section|Chapter|Rule|Part|Title|Schedule|Annex)\s+([IVXLCDM]+)\b/gi,
    (match, keyword, roman) => {
      const num = romanToInt(roman);
      return num ? `${keyword} ${num} (${roman})` : match;
    }
  );

  return result
    .replace(/\u0000/g, '')
    .replace(/[\x00-\x1F\x7F-\x9F]/g, '')
    .replace(/HOME \(HTTPS.*?\)/gi, '')
    .replace(/GOVPH \(.*?\)/gi, '')
    .replace(/\s{2,}/g, ' ')
    .trim();
})() }}

