// LexFlow — Log ingestion to lex_ingestion_log table
// Records what was ingested and when for audit trail.
// If the table doesn't exist yet, this fails silently — won't break the workflow.

const item = $input.first().json;
const supabaseUrl = process.env.SUPABASE_URL || 'https://ncvlpqbevllqwrpdauxi.supabase.co';
const supabaseKey = process.env.SUPABASE_SERVICE_KEY || 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im5jdmxwcWJldmxscXdycGRhdXhpIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjE1NTk2NiwiZXhwIjoyMDg3NzMxOTY2fQ.Cs5k-uKtxyiTejLzsrpJllPg3-cZ6qvFDSjEdEVnBMU';

if (!supabaseKey) {
  return [{ json: { ...item, _log_status: 'skipped — no credentials' } }];
}

const logEntry = {
  law_title:  item.law_title,
  source:     item.source,
  year:       item.year,
  category:   item.category,
  file_id:    item.file_id || '',
  ingested_at: new Date().toISOString(),
  status:     'SUCCESS'
};

try {
  const res = await fetch(`${supabaseUrl}/rest/v1/lex_ingestion_log`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${supabaseKey}`,
      'apikey': supabaseKey,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify(logEntry)
  });
  return [{ json: { ...item, _log_status: res.ok ? 'logged' : `failed: ${res.status}` } }];
} catch (e) {
  return [{ json: { ...item, _log_status: `error: ${e.message}` } }];
}

